var val = Services.getValue(DailyPaymentAmt.dataBinding);
var err = validateCurrencyValue(val, 999999.99 );
if( null == err )
{	var fVal = WPU.formatToTwoDP(Services.getValue(DailyPaymentAmt.dataBinding));
	Services.setValue(DailyPaymentAmt.dataBinding, fVal);
}
return err;

